package com.evolua.user.infrastructure.persistence; import com.evolua.user.domain.Profile; import com.evolua.user.domain.ProfileRepository; import java.util.List; import org.springframework.stereotype.Repository; @Repository public class ProfilePersistenceAdapter implements ProfileRepository { private final ProfileJpaRepository repository; public ProfilePersistenceAdapter(ProfileJpaRepository repository) { this.repository = repository; } public Profile save(Profile item) { ProfileEntity entity = new ProfileEntity(); entity.setId(item.id()); entity.setUserId(item.userId()); entity.setDisplayName(item.displayName()); entity.setBio(item.bio()); entity.setJourneyLevel(item.journeyLevel()); entity.setPremium(item.premium()); entity.setCreatedAt(item.createdAt()); ProfileEntity saved = repository.save(entity); return new Profile(saved.getId(), saved.getUserId(), saved.getDisplayName(), saved.getBio(), saved.getJourneyLevel(), saved.getPremium(), saved.getCreatedAt()); } public List<Profile> findAllByUserId(String userId) { return repository.findAllByUserId(userId).stream().map(saved -> new Profile(saved.getId(), saved.getUserId(), saved.getDisplayName(), saved.getBio(), saved.getJourneyLevel(), saved.getPremium(), saved.getCreatedAt())).toList(); } }
